window.wizardMixin={data(){return{wizardStep:1,totalWizardSteps:8,contentRenderType:1}},computed:{canAdvance(){switch(this.wizardStep){case 2:return!!(this.appName.trim()&&this.appContact.trim());case 6:if(this.typeOfDev==="Individual")return!!this.devName.trim();if(this.typeOfDev==="Company")return!!this.companyName.trim();return false;default:return true}}},methods:{preview(id){this.contentRenderType=1},nextStep(){if(!this.canAdvance)return;this.wizardStep+=1},prevStep(){this.wizardStep-=1}}};window.platformMixin={data(){return{platformType:"Mobile App",deviceType:"mobile device",deviceTypePlural:"mobile devices",platformDesc:"mobile devices",deviceIdDesc:"your mobile device's unique device ID",osDesc:"your mobile operating system",browserDesc:"the type of mobile Internet browsers you use",uninstallDesc:"by uninstalling the Application",osType:"Android",requirementOfSystem:"system"}},computed:{isMobileApp(){return this.platformType==="Mobile App"},isWebApp(){return this.platformType==="Web App"},isBothPlatforms(){return this.platformType==="Both"}},methods:{_setOsRequirement(){switch(this.osType){case"Android & iOS":this.requirementOfSystem="both systems";break;default:this.requirementOfSystem="system"}},_setPlatformText(){switch(this.platformType){case"Web App":this.deviceType="device";this.deviceTypePlural="devices";this.platformDesc="web browsers";this.deviceIdDesc="your device's unique identifier (e.g., IP address or browser fingerprint)";this.osDesc="your operating system";this.browserDesc="the type of web browser you use";this.uninstallDesc="by ceasing to use the website";break;case"Both":this.deviceType="mobile device or computer";this.deviceTypePlural="mobile devices and computers";this.platformDesc="mobile devices and web browsers";this.deviceIdDesc="your device's unique device ID or identifier";this.osDesc="your operating system";this.browserDesc="the type of browser you use";this.uninstallDesc="by uninstalling the Application or ceasing to use the website";break;default:this.deviceType="mobile device";this.deviceTypePlural="mobile devices";this.platformDesc="mobile devices";this.deviceIdDesc="your mobile device's unique device ID";this.osDesc="your mobile operating system";this.browserDesc="the type of mobile Internet browsers you use";this.uninstallDesc="by uninstalling the Application";break}}}};const{createApp}=Vue;const app=createApp({mixins:[window.wizardMixin,window.platformMixin],data(){return{iOrWe:"[I/We]",typeOfApp:"Free",typeOfAppTxt:"a Free",typeOfDev:"Individual",appName:"",appContact:"",businessAddress:"",euRepresentative:"",devName:"",companyName:"",devOrCompanyName:"[Developer/Company name]",pidInfoIn:"",pidInfo:"[add whatever else you collect here, e.g. users name, address, location, pictures]",effectiveFromDate:(new Date).toISOString().slice(0,10),thirdPartyServices:thirdPartyServicesJsonArray,hasThirdPartyServicesSelected:true,showPrivacyModal:false,showGDPRPrivacyModal:false,showNoTrackingPrivacyPolicyModal:false,showTermsModal:false,showDisclaimerModal:false,showFaqModal:false,typeOfPolicy:"Simple",typeOfPolicyInt:1,isLocationTracked:false,ageOfDigitalConsent:16,isAIUsed:false}},computed:{enabledThirdPartyServicesWithPrivacy(){return this.thirdPartyServices.filter(item=>item.enabled&&item.link?.privacy)},enabledThirdPartyServicesWithTerms(){return this.thirdPartyServices.filter(item=>item.enabled&&item.link?.terms)},thirdPartyServicesWithPrivacyOrTerms(){return this.thirdPartyServices.filter(item=>item.link?.privacy||item.link?.terms)}},methods:{capitalize(value){if(!value)return"";return value.charAt(0).toUpperCase()+value.slice(1)},isAppOpenSource(){return this.typeOfApp==="Open Source"},checkForThirdPartyServicesEnabled(){return this.thirdPartyServices.some(item=>item.enabled===true)},toggleState(item){item.enabled=!item.enabled},setTypeOfPolicyInt(){switch(this.typeOfPolicy){case"Simple":this.typeOfPolicyInt=1;break;case"No Tracking":this.typeOfPolicyInt=2;break;case"GDPR":this.typeOfPolicyInt=3;break}},getHtml(id,target){let content=getContent(id);let title=getTitle(id);let rawHTML=getRawHTML(content,title);this.contentRenderType=2;loadInTextView(target,rawHTML)},getMarkdown(id,target){let content=getContent(id);let title=getTitle(id);let rawHTML=getRawHTML(content,title);let markdown=convertHtmlToMd(rawHTML);this.contentRenderType=2;loadInTextView(target,markdown)},generate(){if(!this._validateRequiredFields())return false;this._setDevOrCompanyName();this._setPidInfo();this._setAppTypeText();this._setOsRequirement();this._setPlatformText();return true},_validateRequiredFields(){if(!this.appName.trim())return false;if(!this.appContact.trim())return false;if(this.typeOfDev==="Individual"&&!this.devName.trim())return false;if(this.typeOfDev==="Company"&&!this.companyName.trim())return false;return true},_setDevOrCompanyName(){this.devOrCompanyName=this.typeOfDev==="Individual"?this.devName:this.companyName},_setPidInfo(){this.pidInfo=this.pidInfoIn===""?".":", including but not limited to "+this.pidInfoIn+"."},_setAppTypeText(){this.typeOfAppTxt=["Open Source","Ad Supported"].includes(this.typeOfApp)?"an "+this.typeOfApp:"a "+this.typeOfApp},_toggleModal(modalFlag){if(!this.generate())return;this.hasThirdPartyServicesSelected=this.checkForThirdPartyServicesEnabled();this.contentRenderType=1;this[modalFlag]=!this[modalFlag]},toggleNoTrackingPrivacyPolicyModalVisibility(){if(!this.generate())return;this.contentRenderType=1;this.showNoTrackingPrivacyPolicyModal=!this.showNoTrackingPrivacyPolicyModal},togglePrivacyModalVisibility(){this._toggleModal("showPrivacyModal")},toggleGDPRPrivacyModalVisibility(){this._toggleModal("showGDPRPrivacyModal")},toggleTermsModalVisibility(){this._toggleModal("showTermsModal")},toggleDisclaimerModalVisibility(){this.showDisclaimerModal=!this.showDisclaimerModal},toggleFaqModalVisibility(){this.showFaqModal=!this.showFaqModal},deployFcSimple(){fc_deploy_simple()}}});app.mount("#app");